150		if err != nil {
151			return nil, err
152		}
153	
154		switch {
155		case request.ServiceID != nil && *request.ServiceID != "":
156			return &model.MobileActivateSimResponse{Success: false}, fmt.Errorf("not implemented: use service cli, for now")
157		case request.Cli != nil && *request.Cli != "":
158			res, err := r.SimActivationApiClient.GetUnactivatedSims(ctx, &simactivationservice.GetUnactivatedSimsRequest{AccountNumber: customerAuth.AccountNumber})
159			if err != nil {
160				return &model.MobileActivateSimResponse{Success: false}, err
161			}
162	
163			for _, sim := range res.GetSims() {
164				// If we can find a matching sim that belongs to the mobile platform (has a ServiceID), then we should
165				// activate using the Activate rpc. Otherwise, we should activate using the ActivateLegacy rpc.
166				if sim.GetMsisdn() == *request.Cli && sim.GetServiceId() != "" {
167					_, err = r.SimActivationApiClient.Activate(ctx, &simactivationservice.ActivateRequest{
168						ServiceId: sim.GetServiceId(),
169						Source:    simactivationservice.ActivationSource_SOURCE_MYACCOUNT,
170					})
171					if err != nil {
172						return &model.MobileActivateSimResponse{Success: false}, fmt.Errorf("could not activate platform sim: %w", err)
173					}
174	
175					return &model.MobileActivateSimResponse{Success: true}, nil
176				}
177			}
178	
179			_, err = r.SimActivationApiClient.ActivateLegacy(ctx, &simactivationservice.ActivateLegacyRequest{
180				AccountNumber: customerAuth.AccountNumber,
181				Msisdn:        *request.Cli,
182				Source:        simactivationservice.ActivationSource_SOURCE_MYACCOUNT,
183			})
184			if err != nil {
185				return &model.MobileActivateSimResponse{Success: false}, fmt.Errorf("could not activate legacy sim: %w", err)
186			}
187		default:
188			return &model.MobileActivateSimResponse{Success: false}, fmt.Errorf("either service id or cli is required")
189		}
190	
191		return &model.MobileActivateSimResponse{Success: true}, nil
192	}
