444		auth, err := r.authorize(ctx, cerbos.REPLACE_SIM)
445		if err != nil {
446			return nil, err
447		}
448	
449		overrideAddress := r.getOverrideAddress(request)
450	
451		reason, err := graphqlshared.ParseReplacementReason(request.Reason)
452		if err != nil {
453			return nil, fmt.Errorf("unable to parse replacement reason: %w", err)
454		}
455	
456		simType := graphqlshared.ConvertSimType(request.SimType)
457	
458		resp, err := r.SimReplacementClient.RequestSimReplacement(ctx, &simreplacementservice.RequestSimReplacementRequest{
459			AccountNumber:   auth.AccountNumber,
460			Cli:             request.Cli,
461			Reason:          reason,
462			OverrideAddress: overrideAddress,
463			Channel:         new(AuditChannel),
464			SimType:         simType,
465		})
466		if err != nil {
467			if strings.Contains(err.Error(), replaceerrors.ErrPhoneChangedRecently.Error()) ||
468				strings.Contains(err.Error(), replaceerrors.ErrEmailChangedRecently.Error()) {
469				errorMessage := model.MobileSimReplacementErrorReasonContactDetailsChangedRecently
470				return &model.MobileSimReplacementResponse{
471					ErrorMessage: &errorMessage,
472				}, nil
473			}
474			return nil, fmt.Errorf("unable to request sim replacement: %w", err)
475		}
476	
477		return &model.MobileSimReplacementResponse{
478			SimBarred:             resp.SimBarred,
479			SimReplacementOrdered: resp.SimReplacementOrdered,
480			SimReplacementOnHold:  resp.SimReplacementOnHold,
481		}, nil
482	}
