958		// Identify esim activation communication for this service from returned comms.
959		var esimComm *lecpPb.ResendableCommunication
960		for _, comm := range apiResponse.Resendable {
961			if comm.Type == lecpPb.ResendableType_RESENDABLE_TYPE_ESIM_ACTIVATION_EMAIL &&
962				(comm.ServiceId != nil && *comm.ServiceId == request.ServiceID) {
963				esimComm = comm
964				break
965			}
966		}
967		if esimComm == nil {
968			return &model.MobileCanResendESimActivationEmailResponse{
969				Resendable: false,
970			}, nil
971		}
972	
973		// Build response.
974		response := &model.MobileCanResendESimActivationEmailResponse{
975			Resendable: esimComm.Resendable,
976		}
977		if esimComm.NextSend != nil {
978			nextSendStr := utils.TimestampbbToString(esimComm.NextSend)
