52			OptionTypes: nonEmptyOptionTypes(
53				sharedmodel.MobileHandsetOptionType{Key: "colour", Values: uniqueValues(hs, func(h *handsetpb.Handset) string { return h.GetColours() })},
54				sharedmodel.MobileHandsetOptionType{Key: "storage", Values: uniqueValues(hs, func(h *handsetpb.Handset) string { return h.GetCapacity() })},
55			),
56			Variants: variants,
57		}, nil
58	}
59	
60	func buildVariants(hs []*handsetpb.Handset) []sharedmodel.MobileHandsetVariant {
61		variants := make([]sharedmodel.MobileHandsetVariant, 0, len(hs))
62		for _, h := range hs {
63			variants = append(variants, sharedmodel.MobileHandsetVariant{
64				ID: h.GetId(),
65				Attributes: nonEmptyAttributes(
66					sharedmodel.MobileHandsetAttribute{Key: "colour", Value: h.GetColours()},
67					sharedmodel.MobileHandsetAttribute{Key: "storage", Value: h.GetCapacity()},
68				),
69				MonthlyCharge: &sharedmodel.MobileMoney{Amount: h.GetRentalPrice().GetAmount(), Currency: h.GetRentalPrice().GetCurrency()},
70				Rrp:           &sharedmodel.MobileMoney{Amount: h.GetRrp().GetAmount(), Currency: h.GetRrp().GetCurrency()},
71				InStock:       h.GetInStock(),
72			})
73		}
74		return variants
75	}
76	
77	func lowestPrice(hs []*handsetpb.Handset) (*sharedmodel.MobileMoney, error) {
78		var minPence int32
79		var currency string
80		for _, h := range hs {
81			pence, err := parsePenceFromMoney(h.GetRentalPrice().GetAmount())
82			if err != nil {
83				return nil, fmt.Errorf("invalid rental price for handset %s: %w", h.GetId(), err)
84			}
85			if minPence == 0 || pence < minPence {
86				minPence = pence
87				currency = h.GetRentalPrice().GetCurrency()
88			}
89		}
90		return &sharedmodel.MobileMoney{
91			Amount:   fmt.Sprintf("%.2f", float64(minPence)/100),
92			Currency: currency,
93		}, nil
94	}
95	
96	func uniqueValues(hs []*handsetpb.Handset, get func(*handsetpb.Handset) string) []string {
97		seen := map[string]bool{}
98		var vals []string
99		for _, h := range hs {
100			if v := get(h); v != "" && !seen[v] {
101				seen[v] = true
102				vals = append(vals, v)
103			}
104		}
105		return vals
106	}
107	
108	func nonEmptyOptionTypes(opts ...sharedmodel.MobileHandsetOptionType) []sharedmodel.MobileHandsetOptionType {
109		result := make([]sharedmodel.MobileHandsetOptionType, 0, len(opts))
110		for _, o := range opts {
111			if len(o.Values) > 0 {
112				result = append(result, o)
113			}
114		}
115		return result
116	}
117	
118	func nonEmptyAttributes(attrs ...sharedmodel.MobileHandsetAttribute) []sharedmodel.MobileHandsetAttribute {
119		result := make([]sharedmodel.MobileHandsetAttribute, 0, len(attrs))
120		for _, a := range attrs {
121			if a.Value != "" {
122				result = append(result, a)
123			}
124		}
125		return result
126	}
127	
128	func sortedKeys[V any](m map[string]V) []string {
129		keys := make([]string, 0, len(m))
130		for k := range m {
131			keys = append(keys, k)
132		}
133		sort.Strings(keys)
134		return keys
135	}
