78	func (s *Service) GetAvailableHandsets(ctx context.Context, customerID, serviceID string, includeOutOfStock bool) ([]models.Handset, error) {
79		if serviceID == "" {
80			return nil, fmt.Errorf("service_id is required: %w", terrors.ErrBadRequest)
81		}
82	
83		// If the customer already has an active contract on this service, return empty list
84		_, err := s.store.GetActiveContractForService(ctx, serviceID)
85		if err == nil {
86			tlog.WithAttribute("service_id", serviceID).
87				Info(ctx, "active contract exists, returning empty handset list")
88			return nil, nil
89		}
90		if !errors.Is(err, terrors.ErrNotFound) {
91			return nil, fmt.Errorf("failed to check active contract: %w", err)
92		}
93	
94		err = s.checkPreEligibility(ctx, customerID)
95		if err != nil {
96			return nil, fmt.Errorf("failed pre-eligibility checks: %w", err)
97		}
98	
99		handsets, err := s.store.GetHandsets(ctx, !includeOutOfStock)
100		if err != nil {
101			return nil, fmt.Errorf("failed to get handsets: %w", err)
102		}
103	
104		tlog.WithAttribute("service_id", serviceID).
105			WithAttribute("count", fmt.Sprintf("%d", len(handsets))).
106			Info(ctx, "returning available handsets")
107	
108		return handsets, nil
109	}
