168	func (s *Service) RequestHandsetForService(ctx context.Context, serviceID, customerID, handsetID string) (string, string, error) {
169		if serviceID == "" || customerID == "" || handsetID == "" {
170			return "", "", fmt.Errorf("service_id, customer_id, and handset_id are required: %w", terrors.ErrBadRequest)
171		}
172	
173		if _, err := uuid.Parse(handsetID); err != nil {
174			return "", "", fmt.Errorf("invalid handset_id: %w", terrors.ErrBadRequest)
175		}
176	
177		// Check service belongs to customer
178		servicesResp, err := s.myServicesClient.GetServices(ctx, &myservicesapi.GetServicesRequest{
179			CustomerId:   customerID,
180			IncludeEnded: true,
181		})
182		if err != nil {
183			return "", "", fmt.Errorf("failed to retrieve services for customer: %w", err)
184		}
185	
186		found := false
187		for _, svc := range servicesResp.Services {
188			if svc.GetMobileService() != nil && svc.GetMobileService().GetServiceId() == serviceID {
189				found = true
190				if svc.GetMobileService().GetState() != serviceevents.MobileService_LIVE {
191					return "", "", fmt.Errorf("service is not active: %w", terrors.ErrFailedValidation)
192				}
193				break
194			}
195		}
196		if !found {
197			return "", "", fmt.Errorf("service not found for customer: %w", terrors.ErrNotFound)
198		}
199	
200		// Check for existing active contract
201		_, err = s.store.GetActiveContractForService(ctx, serviceID)
202		if err == nil {
203			return "", "", fmt.Errorf("an active handset contract already exists for this service: %w", terrors.ErrFailedValidation)
204		}
205		if !errors.Is(err, terrors.ErrNotFound) {
206			return "", "", fmt.Errorf("failed to check active contract: %w", err)
207		}
208	
209		err = s.checkPreEligibility(ctx, customerID)
210		if err != nil {
211			return "", "", fmt.Errorf("failed pre-eligibility checks: %w", err)
212		}
213	
214		// Verify handset exists and is in stock
215		h, err := s.store.GetHandsetByID(ctx, handsetID)
216		if err != nil {
217			return "", "", fmt.Errorf("handset not found: %w", terrors.ErrNotFound)
218		}
219		if !h.Active {
220			return "", "", fmt.Errorf("handset is not active: %w", terrors.ErrFailedValidation)
221		}
222		if h.OrdersPlaced >= h.StockBase {
223			return "", "", fmt.Errorf("handset is out of stock: %w", terrors.ErrFailedValidation)
224		}
225	
226		// Atomically reserve a stock slot — conditional $inc rejects if stock is full (concurrent race).
227		if err := s.store.IncrementHandsetOrdersPlaced(ctx, handsetID); err != nil {
228			if errors.Is(err, terrors.ErrNotFound) {
229				return "", "", fmt.Errorf("handset is out of stock: %w", terrors.ErrFailedValidation)
230			}
231			return "", "", fmt.Errorf("failed to reserve handset stock: %w", err)
232		}
233	
234		// Fetch customer information from account-gateway
235		accountResp, err := s.accountClient.GetAccount(ctx, &accountgateway.GetAccountRequest{
236			AccountId: customerID,
237		})
238		if err != nil {
239			s.releaseHandsetStock(ctx, handsetID)
240			return "", "", fmt.Errorf("failed to retrieve account: %w", err)
241		}
242		if accountResp.GetAccount() == nil {
243			s.releaseHandsetStock(ctx, handsetID)
244			return "", "", fmt.Errorf("account response missing account data")
245		}
246	
247		now := time.Now()
248		props := h.CurrentProperties
249		contract := models.Contract{
250			ID:                 uuid.New().String(),
251			ServiceID:          serviceID,
252			CustomerID:         customerID,
253			HandsetID:          handsetID,
254			HandsetName:        fmt.Sprintf("%s %s", props.Manufacturer, props.Model),
255			HandsetVersion:     props.Version,
256			ContractPricePence: fmt.Sprintf("%d", props.RentalPricePence),
257			RetailPricePence:   fmt.Sprintf("%d", props.RRPPence),
258			ContractMonths:     fmt.Sprintf("%d", props.ContractTermMonths),
259			RequestID:          uuid.New().String(),
260			Status:             models.ContractStatusPendingEligibility,
261			CreatedAt:          now,
262			UpdatedAt:          now,
263		}
264	
265		if err = s.store.CreateContract(ctx, contract); err != nil {
266			s.releaseHandsetStock(ctx, handsetID)
267			return "", "", fmt.Errorf("failed to create contract: %w", err)
268		}
269	
270		tlog.WithAttribute("service_id", contract.ServiceID).
271			WithAttribute("customer_id", contract.CustomerID).
272			WithAttribute("contract_id", contract.ID).
273			WithAttribute("request_id", contract.RequestID).
274			WithAttribute("handset_id", contract.HandsetID).
275			Info(ctx, "handset contract created")
276	
277		// Produce lifecycle event
278		if err := s.eventProducer.ProduceMobileHandsetContractRequestedSync(ctx, &serviceevents.MobileHandsetContractRequested{
279			ServiceId:  contract.ServiceID,
280			CustomerId: contract.CustomerID,
281			ContractId: contract.ID,
282			HandsetId:  contract.HandsetID,
283		}); err != nil {
284			tlog.WithError(err).
285				WithAttribute("contract_id", contract.ID).
286				Error(ctx, "failed to produce MobileHandsetContractRequested event")
287		}
288	
289		redirectURL, err := eligibilityRedirectURL(s.eligibilityProviderURL, contract.RequestID)
290		if err != nil {
291			return "", "", err
292		}
293	
294		return contract.RequestID, redirectURL, nil
295	}
