349	// EligibilityCallbackFailure handles a failure callback from the eligibility provider,
350	// indicating the eligibility process could not be completed (e.g. KYC or credit check failure).
351	func (s *Service) EligibilityCallbackFailure(ctx context.Context, requestID string, outcome models.EligibilityFailureOutcome) error {
352		if requestID == "" {
353			return fmt.Errorf("request_id is required: %w", terrors.ErrBadRequest)
354		}
