356		contract, err := s.store.GetContractByRequestID(ctx, requestID)
357		if err != nil {
358			return fmt.Errorf("failed to get contract: %w", err)
359		}
360	
361		if contract.Status != models.ContractStatusPendingEligibility {
362			tlog.WithAttribute("request_id", requestID).
363				WithAttribute("current_status", string(contract.Status)).
364				Info(ctx, "eligibility failure callback ignored, contract is not pending eligibility")
365			return nil
366		}
367	
368		if err := s.store.UpdateContractEligibilityFailed(ctx, requestID, outcome); err != nil {
369			return fmt.Errorf("failed to update contract status: %w", err)
370		}
371	
372		s.releaseHandsetStock(ctx, contract.HandsetID)
373	
374		if err := s.eventProducer.ProduceMobileHandsetContractDeclinedSync(ctx, &serviceevents.MobileHandsetContractDeclined{
375			ServiceId:  contract.ServiceID,
376			CustomerId: contract.CustomerID,
377			ContractId: contract.ID,
378			HandsetId:  contract.HandsetID,
379		}); err != nil {
380			tlog.WithError(err).
381				WithAttribute("contract_id", contract.ID).
382				Error(ctx, "failed to produce MobileHandsetContractDeclined event")
383		}
384	
385		tlog.WithAttribute("request_id", requestID).
386			WithAttribute("contract_id", contract.ID).
387			Info(ctx, "eligibility failed, contract declined")
388	
389		return nil
390	}
